41	 *
42	 *   - Seeds local draft state from the assignments coming off the receipt.
43	 *   - Re-seeds when the underlying assignments change (add/remove/remote update).
44	 *   - Debounces per-row writes back to Zero so slider drags coalesce into a
45	 *     single mutator call per row.
46	 *   - Exposes ready-to-render `entries` and `roundedPercents` plus the three
47	 *     handlers the view needs.
48	 *
49	 * All numerical work is delegated to the pure helpers in `../utils/split-percent`.
50	 */
51	export function useSplitPercent({
52	  item,
53	}: UseSplitPercentArgs): UseSplitPercentResult {
54	  const zero = useZero();
55	
56	  // Only active assignments participate in the split; soft-deleted rows would
57	  // otherwise skew the even-share fallback and show ghost rows in the UI.
58	  const activeAssignments = useMemo(
59	    () => item.assignments.filter((assignment) => !assignment.deletedAt),
60	    [item.assignments]
61	  );
62	
63	  // Build a stable key that changes whenever any assignment id, share, or
64	  // lock flag changes. Used to re-seed local state from the source of truth.
65	  const seedKey = useMemo(
66	    () =>
67	      activeAssignments
68	        .map(
69	          (assignment) =>
70	            `${assignment.id}:${assignment.sharePercentage?.toString() ?? 'null'}:${assignment.locked ? 1 : 0}`
71	        )
72	        .join('|'),
73	    [activeAssignments]
74	  );
75	
76	  // Derive the initial draft entries from the receipt's assignments. Rows
77	  // without an explicit share fall back to an even split across participants.
78	  const seedEntries = useMemo<DraftEntry[]>(() => {
79	    const participantCount = activeAssignments.length;
80	    const fallbackShare = evenShares(participantCount);
81	
82	    return activeAssignments.map((assignment) => {
83	      let share: Decimal;
84	      if (assignment.sharePercentage != null) {
85	        // Persisted custom share exists → honor it.
86	        share = assignment.sharePercentage;
87	      } else {
88	        // No persisted share yet → seed from the even-split fallback.
89	        share = fallbackShare;
90	      }
91	
92	      return {
93	        id: assignment.id,
94	        receiptUserId: assignment.receiptUserId,
95	        displayName: getUserDisplayName(assignment),
96	        share,
97	        locked: assignment.locked,
98	      };
99	    });
100	  }, [activeAssignments]);
101	
102	  const [entries, setEntries] = useState<DraftEntry[]>(seedEntries);
103	
104	  // Re-seed whenever the upstream assignments change so remote edits and
105	  // add/remove operations are reflected locally.
106	  useEffect(() => {
107	    setEntries(seedEntries);
108	  }, [seedKey, seedEntries]);
109	
110	  // Per-assignment debounce timers. Kept in a ref so re-renders don't reset
111	  // pending writes mid-flight.
112	  const persistTimers = useRef<Map<string, ReturnType<typeof setTimeout>>>(
113	    new Map()
114	  );
115	
116	  useEffect(() => {
117	    const timers = persistTimers.current;
118	    return () => {
119	      for (const timer of timers.values()) {
120	        clearTimeout(timer);
121	      }
122	      timers.clear();
123	    };
124	  }, []);
125	
126	  const persistShare = useCallback(
127	    (assignmentId: string, share: Decimal) => {
128	      // Replace any in-flight timer for this row so rapid slider moves
129	      // coalesce into a single mutator call.
130	      const existing = persistTimers.current.get(assignmentId);
131	      if (existing) {
132	        clearTimeout(existing);
133	      }
134	
135	      const timer = setTimeout(() => {
136	        void zero.mutate(
137	          mutators.assignments.update({
138	            id: assignmentId,
139	            share_percentage: share.toNumber(),
140	          })
141	        );
142	        persistTimers.current.delete(assignmentId);
143	      }, PERSIST_DEBOUNCE_MS);
144	
145	      persistTimers.current.set(assignmentId, timer);
146	    },
147	    [zero]
148	  );
149	
150	  const persistChangedShares = useCallback(
151	    (next: DraftEntry[], previous: DraftEntry[]) => {
152	      // Diff each row so we only schedule a write when its share actually
153	      // moved. Sibling rebalancing legitimately touches every unlocked row.
154	      for (const entry of next) {
155	        const prev = previous.find((candidate) => candidate.id === entry.id);
156	        if (!prev || !prev.share.equals(entry.share)) {
157	          persistShare(entry.id, entry.share);
158	        }
159	      }
160	    },
161	    [persistShare]
162	  );
163	
164	  const handleChange = useCallback(
165	    (assignmentId: string, value: Decimal) => {
166	      setEntries((prev) => {
167	        // Delegate the math to the pure module and persist any row whose
168	        // share ended up different from its previous value.
169	        const next = rebalance(prev, assignmentId, value) as DraftEntry[];
170	        persistChangedShares(next, prev);
171	        return next;
172	      });
173	    },
174	    [persistChangedShares]
175	  );
